<script>
  const TOTAL = 5;
  const state = { active: 1, done: new Set() };

  function updateProgress() {
    const count = state.done.size;
    document.getElementById('progress-label').textContent = `${count} / ${TOTAL}`;
    document.getElementById('progress-fill').style.width = `${(count / TOTAL) * 100}%`;
    updateNavDots();
  }

  function updateNavDots() {
    const container = document.getElementById('nav-dots');
    container.innerHTML = '';
    for (let i = 1; i <= TOTAL; i++) {
      const dot = document.createElement('div');
      dot.className = 'nav-dot';
      if (state.done.has(i)) dot.classList.add('done');
      else if (state.active === i) dot.classList.add('active');
      dot.onclick = () => activateStep(i);
      container.appendChild(dot);
    }
  }

  function activateStep(n) {
    for (let i = 1; i <= TOTAL; i++) {
      const el = document.getElementById(`step-${i}`);
      const num = document.getElementById(`num-${i}`);
      el.classList.remove('active');
      if (state.done.has(i)) {
        el.classList.add('done');
        num.textContent = '✓';
      } else {
        el.classList.remove('done');
        num.textContent = String(i).padStart(2, '0');
      }
    }
    state.active = n;
    const activeEl = document.getElementById(`step-${n}`);
    activeEl.classList.remove('done');
    activeEl.classList.add('active');
    updateProgress();
  }

  function completeStep(n, e) {
    e.stopPropagation();
    state.done.add(n);
    const next = n + 1;
    if (next <= TOTAL) {
      activateStep(next);
      setTimeout(() => {
        document.getElementById(`step-${next}`).scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 100);
    } else {
      activateStep(n);
      document.getElementById('final-card').classList.add('visible');
      setTimeout(() => {
        document.getElementById('final-card').scrollIntoView({ behavior: 'smooth', block: 'start' });
      }, 100);
    }
    updateProgress();
  }

  function toggleCheck(el) {
    el.classList.toggle('checked');
  }

  function copyCode(btn) {
    const pre = btn.closest('.code-block').querySelector('pre');
    const text = pre.innerText;
    navigator.clipboard.writeText(text).then(() => {
      btn.textContent = 'copied!';
      btn.classList.add('copied');
      setTimeout(() => {
        btn.textContent = 'copy';
        btn.classList.remove('copied');
      }, 2000);
    });
  }

  updateNavDots();
</script>
