.pc-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 18px;
  border-bottom: 1px solid var(--border);
  background: var(--bg3);
}
.pc-left { display: flex; align-items: center; gap: 10px; }
.pc-tag {
  font-size: 10px;
  font-family: var(--mono);
  font-weight: 600;
  padding: 3px 8px;
  border-radius: 4px;
  letter-spacing: 0.04em;
}
.tag-global   { background: var(--purple-d); color: var(--purple); }
.tag-context  { background: var(--teal-d);   color: var(--teal); }
.tag-project  { background: var(--amber-d);  color: var(--amber); }
.tag-dispatch { background: var(--coral-d);  color: var(--coral); }
.tag-schedule { background: var(--blue-d);   color: var(--blue); }
.tag-file     { background: var(--green-d);  color: var(--green); }

.pc-filename {
  font-size: 12px;
  font-family: var(--mono);
  color: var(--text2);
}
.pc-copy {
  font-size: 11px;
  font-family: var(--mono);
  color: var(--text3);
  background: none;
  border: 1px solid var(--border2);
  border-radius: 5px;
  padding: 4px 12px;
  cursor: pointer;
  transition: all 0.15s;
}
.pc-copy:hover { color: var(--teal); border-color: var(--teal); }
.pc-copy.ok   { color: var(--green); border-color: var(--green); }

.pc-body {
  padding: 18px 20px;
  font-family: var(--mono);
  font-size: 12.5px;
  line-height: 1.85;
  color: #c0c9da;
  white-space: pre-wrap;
  word-break: break-word;
}

/* Syntax highlight inside prompt */
.ph-head   { color: var(--purple); font-weight: 600; }
.ph-sub    { color: var(--blue); }
.ph-val    { color: var(--teal); }
.ph-arrow  { color: var(--amber); }
.ph-note   { color: var(--text3); font-style: italic; }
.ph-em     { color: #f3f4f6; font-weight: 500; }
.ph-rule   { color: var(--coral); }

/* ── Callout ── */
.callout {
  display: flex;
  gap: 12px;
  padding: 14px 16px;
  border-radius: 8px;
  font-size: 12.5px;
  line-height: 1.65;
  margin-bottom: 16px;
}
.ca-teal   { background: var(--teal-d);  border: 1px solid rgba(52,211,153,0.2);  color: #6ee7b7; }
.ca-amber  { background: var(--amber-d); border: 1px solid rgba(251,191,36,0.2);  color: #fcd34d; }
.ca-purple { background: var(--purple-d);border: 1px solid rgba(167,139,250,0.2); color: #c4b5fd; }
.ca-icon   { font-size: 14px; flex-shrink: 0; margin-top: 1px; }

/* ── Setup steps ── */
.steps { display: flex; flex-direction: column; gap: 12px; margin-bottom: 20px; }
.step-row {
  display: flex;
  gap: 14px;
  align-items: flex-start;
}
.step-num-box {
  width: 26px; height: 26px;
  border-radius: 6px;
  background: var(--purple-d);
  border: 1px solid rgba(167,139,250,0.25);
  display: flex; align-items: center; justify-content: center;
  font-size: 11px; font-weight: 600; color: var(--purple);
  font-family: var(--mono); flex-shrink: 0; margin-top: 1px;
}
.step-content { font-size: 13px; color: var(--text2); padding-top: 3px; }
.step-content strong { color: var(--text); font-weight: 500; }
.step-content code {
  font-family: var(--mono); font-size: 11.5px;
  background: var(--bg3); border: 1px solid var(--border2);
  border-radius: 4px; padding: 1px 6px; color: var(--teal);
}

/* ── Divider ── */
.divider {
  border: none;
  border-top: 1px solid var(--border);
  margin: 32px 0;
}

/* ── Scrollbar ── */
::-webkit-scrollbar { width: 5px; height: 5px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--bg4); border-radius: 3px; }
</style>
</head>
